}: SortVariables
*/

import React from "react";
import Link from "next/link";

interface SortVariables {
  SortOrder: string;
  SortByUser: string;
  SortByStatus: string;
}

const JobCards = async () => {
  // Fallback zur localhost:3213, falls env nicht gesetzt
  const baseUrl = process.env.NEXT_PUBLIC_BACKEND_URL || "http://localhost:3213";

  let jobs: [string, any][] = [];
  let errorMsg = "";

  try {
    const res = await fetch(`${baseUrl}/api/jobs`, {
      cache: "no-store",
    });

    if (!res.ok) {
      throw new Error(`Backend returned status ${res.status}`);
    }

    const data = await res.json();
    jobs = Object.entries(data); // [ ['123', {...}], ['124', {...}] ]
  } catch (error) {
    errorMsg = error instanceof Error ? error.message : String(error);
  }

  // Helper: Glow-Farbe pro Status
  const getGlowColor = (status: string | null | undefined): string => {
    if (!status) return "rgba(59,130,246,0.12)"; // default blue
    const s = String(status).toLowerCase();
    if (s.includes("queue")) return "rgba(250,204,21,0.14)"; // yellow
    if (s.includes("render") || s.includes("running")) return "rgba(16,185,129,0.14)"; // green
    if (s.includes("error") || s.includes("failed") || s.includes("cancel")) return "rgba(239,68,68,0.16)"; // red
    if (s.includes("octree") || s.includes("generating")) return "rgba(168,85,247,0.14)"; // purple
    return "rgba(59,130,246,0.12)"; // default blue
  };

  if (errorMsg) {
    return (
      <div className="alert alert-error shadow-lg">
        <div>
          <h3 className="font-bold">Failed to load jobs</h3>
          <p className="text-sm">{errorMsg}</p>
          <p className="text-xs mt-1">Backend URL: {baseUrl}</p>
        </div>
      </div>
    );
  }

  if (jobs.length === 0) {
    return (
      <div className="alert alert-info shadow-lg">
        <div>
          <h3 className="font-bold">No jobs found</h3>
          <p className="text-sm">No job data available from backend.</p>
        </div>
      </div>
    );
  }

  return (
    <>
      {/* Inline CSS für Job-Card Glow-Effekt */}
      <style>{`
        .job-card {
          transition: box-shadow 200ms ease;
          box-shadow: 0 6px 18px rgba(0,0,0,0.35);
          border-radius: 0.5rem;
          border: 1px solid rgba(255,255,255,0.04);
        }
        .job-card:hover {
          box-shadow: 0 0 30px var(--job-card-glow, rgba(59,130,246,0.12));
        }
        .job-card .card-body img {
          display: block;
          max-width: 100%;
          height: auto;
        }
      `}</style>

      {jobs.map(([id, job]: [string, any]) => (
        <Link key={id} href={`/jobs/${id}`} className="block mb-4">
          <div
            className="card flex w-full bg-gray-800 text-white shadow-lg job-card cursor-pointer"
            style={{ ["--job-card-glow" as any]: getGlowColor(job.status) } as React.CSSProperties}
          >
            <div className="card-body p-4">
              <h2 className="card-title text-lg">{id}</h2>
              <img src="/images/blueprint.png" alt="Job Thumbnail" width={1200} height={800} />
              <p className="text-sm">
                SPP: {job.spp} / {job.targetSpp}
              </p>
              <p className="text-sm">Status: <span className="font-semibold">{job.status ?? "Unbekannt"}</span></p>
              <p className="text-xs text-gray-400">Created: {new Date(job.created).toLocaleString()}</p>
            </div>
          </div>
        </Link>
      ))}
    </>
  );
};

export default JobCards;

