import { useEffect, useState } from "react";
import { useRouter } from "next/router";
import Head from "next/head";
import Header from "../../components/Header";

function useJob(id, initialData) {
  const [job, setJob] = useState(initialData);
  useEffect(() => {
    let stale = false;
    async function loadJob() {
      const res = await fetch(`http://localhost:3001/api/jobs/${id}`);
      if (res.status === 200) {
        const json = await res.json();
        if (!stale) {
          setJob(json);
        }
      } else {
        setJob(null);
      }
    }
    let interval;
    if (id) {
      interval = setInterval(() => loadJob(), 30000);
    }
    return () => {
      stale = true;
      setJob(null);
      if (interval) {
        clearInterval(interval);
      }
    };
  }, [id]);
  return job;
}

export async function getServerSideProps(context) {
  const res = await fetch(
    `http://localhost:3213/api/jobs/${context.params.id}`
  );
  const data = await res.json();

  return {
    props: {
      initialData: data,
    },
  };
}

export default function JobDetails({ initialData }) {
  const router = useRouter();
  const { id } = router.query;

  const job = useJob(id, initialData);

  return (
    <div>
      <Head>
        <title>Job {id} – ChunkyCloud</title>
      </Head>
      <Header title={id} breadcrumbs={[{ title: "Jobs" }]} />
      {job.spp > 0 && (
        <a
          href={`http://localhost:3213/api/jobs/${id}/latest.png?${job.spp}`}
          target="_blank"
          rel="noreferrer"
        >
          <img
            src={`http://localhost:3213/api/jobs/${id}/latest.png?${job.spp}`}
            alt="Not available yet"
            width="500"
          />
        </a>
      )}
      {job && (
        <table>
          <tbody>
            <tr>
              <th>Resolution</th>
              <td>
                {job.sceneDescription?.width} × {job.sceneDescription?.height}
              </td>
            </tr>
            <tr>
              <th>Ray depth</th>
              <td>{job.sceneDescription?.rayDepth}</td>
            </tr>
            <tr>
              <th>
                <abbr title="Samples per pixel">SPP</abbr>
              </th>
              <td>
                {job.spp.toLocaleString()}/{job.targetSpp.toLocaleString()} (
                {Math.round((job.spp / job.targetSpp) * 100)}%)
                {job.spp > 0 && !job.pictureOnly && (
                  <>
                    {" "}
                    <a
                      href={`http://localhost:3213/api/jobs/${id}/latest.dump`}
                      target="_blank"
                      rel="noreferrer"
                      download
                    >
                      Download dump
                    </a>
                  </>
                )}
              </td>
            </tr>
            <tr>
              <th>Created at</th>
              <td>{new Date(job.created).toLocaleString()}</td>
            </tr>
            <tr>
              <th>Finished at</th>
              <td>
                {job.finishedAt
                  ? new Date(job.finishedAt).toLocaleString()
                  : job.cancelled
                  ? "Cancelled"
                  : "n/a"}
              </td>
            </tr>
            {!job.cancelled && (
              <>
                <tr>
                  <th>
                    Total time<sup>(1)</sup>
                  </th>
                  <td>
                    <Duration start={job.created} end={job.finishedAt} />
                  </td>
                </tr>
                <tr>
                  <th>
                    Effective <abbr title="Samples per second">SPS</abbr>
                    <sup>(2)</sup>
                  </th>
                  <td>
                    {job.spp > 0
                      ? (
                          (job.spp *
                            job.sceneDescription?.width *
                            job.sceneDescription?.height) /
                          ((Date.parse(
                            job.finishedAt || new Date().toISOString()
                          ) -
                            Date.parse(job.created)) /
                            1000)
                        ).toLocaleString(undefined, {
                          maximumFractionDigits: 2,
                        })
                      : "n/a"}
                  </td>
                </tr>
              </>
            )}
            {job.renderTime > 0 && (
              <>
                <tr>
                  <th>
                    Render time<sup>(3)</sup>
                  </th>
                  <td>
                    <Duration
                      start={new Date(0)}
                      end={new Date(job.renderTime * 1000)}
                    />
                  </td>
                </tr>
                <tr>
                  <th>
                    Average <abbr title="Samples per second">SPS</abbr>
                    <sup>(4)</sup>
                  </th>
                  <td>
                    {(
                      (job.spp *
                        job.sceneDescription?.width *
                        job.sceneDescription?.height) /
                      job.renderTime
                    ).toLocaleString(undefined, {
                      maximumFractionDigits: 2,
                    })}
                  </td>
                </tr>
              </>
            )}
          </tbody>
        </table>
      )}
      <p style={{ fontSize: "0.8rem" }}>
        <sup>1</sup>Actual time between the job being created and finished.
        Includes time spent waiting for workers and transmitting files.
        <br />
        <sup>2</sup>Total samples divided by the total time
        <br />
        <sup>3</sup>Sum of the render times of all merged dumps of this job.
        Does not include time spent downloading, loading, saving or uploading
        the scene files.
        <br />
        <sup>4</sup>Total samples divided by the render time, resulting in the
        average SPS of the involved render nodes
      </p>
    </div>
  );
}

function Duration({ start, end }) {
  const [actualEnd, setActualEnd] = useState(end || new Date());
  useEffect(() => {
    if (end) {
      setActualEnd(end);
    } else {
      const interval = setInterval(() => {
        setActualEnd(new Date());
      }, 1000);
      return () => clearInterval(interval);
    }
  }, [end]);

  const delta = Math.max(0, Date.parse(actualEnd) - Date.parse(start)) / 1000;
  const h = Math.floor(delta / (60 * 60));
  const m = Math.floor((delta % (60 * 60)) / 60);
  const s = Math.floor(delta % 60);
  return `${`${h}`.padStart(2, "0")}:${`${m}`.padStart(
    2,
    "0"
  )}:${`${s}`.padStart(2, "0")}`;
}

// Deprecated pages-style job detail. Using app router implementation at
// app/jobs/[id]/page.tsx instead. Kept for reference.

export default function DeprecatedJobDetail() {
  return null;
}

import Head from "next/head";
import { useEffect, useState } from "react";
import Icon from "@mdi/react";
import { mdiCog, mdiDesktopTower } from "@mdi/js";
import Header from "../components/Header";
import styles from "../styles/Stats.module.css";
import contentStyles from "../styles/Content.module.css";

function useStats(initialStats) {
  const [stats, setStats] = useState(initialStats);
  useEffect(() => {
    let stale = false;
    async function loadStats() {
      const res = await fetch(`http://localhost:3213/api/stats`, {
        mode: "no-cors",
      });
      if (res.status === 200) {
        const json = await res.json();
        if (!stale) {
          setStats(json);
        }
      }
    }
    const interval = setInterval(() => loadStats(), 30000);
    return () => {
      stale = true;
      setStats(null);
      if (interval) {
        clearInterval(interval);
      }
    };
  }, []);
  return stats;
}

export async function getServerSideProps(context) {
  const res = await fetch(`http://localhost:3213/api/stats`);
  const data = await res.json();

  return {
    props: {
      initialStats: data,
    },
  };
}

export default function Stats({ initialStats }) {
  const stats = useStats(initialStats);

  return (
    <div>
      <Head>
        <title>Statistics – ChunkyCloud</title>
        <link rel="icon" href="/favicon.ico" />
      </Head>
      <Header title="Statistics" />
      <div className={contentStyles.content}>
        <h1>ChunkyCloud statistics</h1>
        {stats && (
          <>
            <div className={styles.queue}>
              <div className={styles.step}>
                <div>{stats.tasks.preparePending.toLocaleString()}</div>
                <div>Queue</div>
              </div>
              <div className={styles.step}>
                <div>{stats.tasks.prepareRunning.toLocaleString()}</div>
                <div>Generating octree</div>
              </div>
              <div className={styles.step}>
                <div>{stats.tasks.pending.toLocaleString()}</div>
                <div>Queue</div>
              </div>
              <div className={styles.step}>
                <div>{stats.tasks.running.toLocaleString()}</div>
                <div>Rendering</div>
              </div>
              <div className={styles.step}>
                <div>
                  {(
                    stats.tasks.mergePending + stats.tasks.mergeRunning
                  ).toLocaleString()}
                </div>
                <div>Merging</div>
              </div>
            </div>
            <div className={styles.today}>
              <div className={styles.number}>
                <div>{stats.today.jobsCreated.toLocaleString()}</div>
                <div>Jobs created today</div>
              </div>
              <div className={styles.number}>
                <div>{stats.today.jobsFinished.toLocaleString()}</div>
                <div>Jobs finished today</div>
              </div>
              <div className={styles.number}>
                <div>{stats.today.dumpsMerged.toLocaleString()}</div>
                <div>Dumps merged today</div>
              </div>
            </div>
            <h2>
              Render nodes{" "}
              <small>
                {`${stats.renderNodes
                  .filter((node) => node.status === "working")
                  .length.toLocaleString()} of ${stats.renderNodes.length.toLocaleString()} nodes working (${stats.renderNodes
                  .filter((node) => node.status === "working")
                  .reduce((sum, node) => sum + node.threads, 0)
                  .toLocaleString()} of ${stats.renderNodes
                  .reduce((sum, node) => sum + node.threads, 0)
                  .toLocaleString()} threads)`}
              </small>
            </h2>
            <div className={styles.nodes}>
              {stats.renderNodes.map((node, i) => (
                <div
                  key={i}
                  className={`${styles.node} ${
                    node.status === "working" ? styles.active : ""
                  }`}
                >
                  <div>
                    <Icon path={mdiDesktopTower} size={1.5} horizontal />
                    {node.status === "working" && (
                      <Icon
                        path={mdiCog}
                        size={0.75}
                        spin={-5}
                        className={styles.cog}
                      />
                    )}
                  </div>
                  <span title={node.name}>{node.name}</span>
                  <span>
                    {node.threads} {node.threads > 1 ? "threads" : "thread"}
                  </span>
                </div>
              ))}
            </div>

            <h2>
              Region processing nodes{" "}
              <small>
                {`${stats.prepareNodes
                  .filter((node) => node.status === "working")
                  .length.toLocaleString()} of ${stats.prepareNodes.length.toLocaleString()} nodes working`}
              </small>
            </h2>
            <div className={styles.nodes}>
              {stats.prepareNodes.map((node, i) => (
                <div
                  key={i}
                  className={`${styles.node} ${
                    node.status === "working" ? styles.active : ""
                  }`}
                >
                  <div>
                    <Icon path={mdiDesktopTower} size={1.5} horizontal />
                    {node.status === "working" && (
                      <Icon
                        path={mdiCog}
                        size={0.75}
                        spin={-5}
                        className={styles.cog}
                      />
                    )}
                  </div>
                  <span title={node.name}>{node.name}</span>
                </div>
              ))}
            </div>
          </>
        )}
        <hr />
        <h2>How ChunkyCloud works</h2>
        <p>
          A scene that is to be rendered is called a <em>render job</em>. Render
          jobs get split up into one or many <em>tasks</em> that are rendered on
          the <em>render nodes</em>. The number of tasks a job is split into
          depends on its resolution and samples per pixel.
        </p>
        <p>
          Instead of starting with an octree and an emittergrid, scenes can also
          be created from region files. ChunkyMap can use this so it doesn't
          need to construct the octree on a Minecraft server. New jobs that are
          created from region files are put in the{" "}
          <em>region processing queue</em> first and added to the{" "}
          <em>render queue</em> after a <em>region processing node</em> has
          created the scene files.
        </p>
        <p>
          When a <em>task</em> is done, it needs to be merged with the part of
          the <em>job</em> that is already done. This is done by a single{" "}
          <em>dump processor</em> that also has a queue of dumps waiting to be
          merged.
        </p>
        <p>
          If a job gets cancelled, it is not removed from the queues. The nodes
          will check if it is cancelled and just skip them in that case.
        </p>
      </div>
    </div>
  );
}

