  const newId = String(
    Math.max(...Object.keys(jobs).map(Number)) + 1
  );

  const newJob = {
    id: newId,
    spp: 0,
    targetSpp: 500,
    sceneDescription: {
      width: 1920,
      height: 1080,
      rayDepth: 5,
    },
    created: new Date().toISOString(),
    finishedAt: null,
    status: "queued",
    cancelled: false,
    renderTime: 0,
  };

  jobs[newId] = newJob;

  res.status(201).json({
    _id: newId,
  });
});

